3	const buildPageItems = (currentPage, totalPages) => {
4	    if (totalPages <= 1) return [];
5	    if (totalPages <= 7) {
6	        return Array.from({ length: totalPages }, (_, i) => ({ type: 'page', value: i + 1 }));
7	    }
8	    const pages = new Set([1, totalPages, currentPage - 1, currentPage, currentPage + 1]);
9	    const ordered = [...pages].filter((p) => p >= 1 && p <= totalPages).sort((a, b) => a - b);
10	    const items = [];
11	    let last = 0;
12	    ordered.forEach((p) => {
13	        if (p - last > 1) items.push({ type: 'ellipsis', key: `e-${last}-${p}` });
14	        items.push({ type: 'page', value: p });
15	        last = p;
16	    });
17	    return items;
18	};
